  1→package com.exam.controller;
  2→
  3→import com.exam.dto.Result;
  4→import com.exam.dto.UserInfo;
  5→import com.exam.entity.SysUser;
  6→import com.exam.service.AuthService;
  7→import jakarta.servlet.http.HttpServletRequest;
  8→import lombok.extern.slf4j.Slf4j;
  9→import org.springframework.beans.factory.annotation.Value;
 10→import org.springframework.core.env.Environment;
 11→import org.springframework.http.HttpHeaders;
 12→import org.springframework.http.HttpStatus;
 13→import org.springframework.http.ResponseEntity;
 14→import org.springframework.security.core.Authentication;
 15→import org.springframework.security.core.context.SecurityContextHolder;
 16→import org.springframework.web.bind.annotation.*;
 17→import org.springframework.web.util.UriComponentsBuilder;
 18→
 19→import java.util.Arrays;
 20→import java.util.List;
 21→import java.util.Map;
 22→
 23→/**
 24→ * 认证接口：OAuth2 登录、回调、获取当前用户
 25→ */
 26→@Slf4j
 27→@RestController
 28→@RequestMapping("/api/auth")
 29→public class AuthController {
 30→
 31→    private final AuthService authService;
 32→    private final Environment environment;
 33→
 34→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 35→    private String clientId;
 36→
 37→    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
 38→    private String authorizationUri;
 39→
 40→    @Value("${spring.security.oauth2.client.registration.default.scope:openid,profile,email}")
 41→    private String scope;
 42→
 43→    @Value("${app.frontend-url:http://localhost:5173}")
 44→    private String frontendUrl;
 45→
 46→    public AuthController(AuthService authService, Environment environment) {
 47→        this.authService = authService;
 48→        this.environment = environment;
 49→    }
 50→
 51→    private boolean isDevProfile() {
 52→        return Arrays.asList(environment.getActiveProfiles()).contains("dev");
 53→    }
 54→
 55→    /**
 56→     * 构建 OA 授权地址并 302 重定向；dev 环境直接签发 JWT 跳回前端
 57→     */
 58→    @GetMapping("/oauth2/login")
 59→    public ResponseEntity<Void> login(HttpServletRequest request) {
 60→        if (isDevProfile()) {
 61→            String token = authService.devLogin();
 62→            String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
 63→            log.info("[lbl][Auth][LOGIN] Dev 模式: 跳过 OAuth2, 直接重定向到前端");
 64→            return ResponseEntity.status(HttpStatus.FOUND)
 65→                    .header(HttpHeaders.LOCATION, callbackUrl)
 66→                    .build();
 67→        }
 68→
 69→        String redirectUri = buildRedirectUri(request);
 70→
 71→        String authorizeUrl = UriComponentsBuilder.fromHttpUrl(authorizationUri)
 72→                .queryParam("client_id", clientId)
 73→                .queryParam("redirect_uri", redirectUri)
 74→                .queryParam("response_type", "code")
 75→                .queryParam("scope", scope)
 76→                .toUriString();
 77→
 78→        log.debug("[lbl][Auth][LOGIN] OAuth2 登录重定向: {}", authorizeUrl);
 79→
 80→        return ResponseEntity.status(HttpStatus.FOUND)
 81→                .header(HttpHeaders.LOCATION, authorizeUrl)
 82→                .build();
 83→    }
 84→
 85→    /**
 86→     * OAuth2 回调：用 code 换 token，302 重定向到前端并携带 token
 87→     */
 88→    @GetMapping("/oauth2/callback")
 89→    public ResponseEntity<Void> callback(@RequestParam("code") String code,
 90→                                         HttpServletRequest request) {
 91→        String redirectUri = buildRedirectUri(request);
 92→        String token = authService.handleOAuthCallback(code, redirectUri);
 93→        log.info("[lbl][Auth][CALLBACK] OAuth2 回调完成, 已签发 token, 重定向到前端");
 94→
 95→        String callbackUrl = frontendUrl + "/oauth/callback?token=" + token;
 96→        return ResponseEntity.status(HttpStatus.FOUND)
 97→                .header(HttpHeaders.LOCATION, callbackUrl)
 98→                .build();
 99→    }
100→
101→    /**
102→     * 获取当前登录用户信息
103→     */
104→    @GetMapping("/me")
105→    public Result<UserInfo> me() {
106→        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
107→        Long userId = Long.parseLong(auth.getName());
108→        UserInfo userInfo = authService.getCurrentUser(userId);
109→        return Result.ok(userInfo);
110→    }
111→
112→    /**
113→     * Dev 环境批量注册 mock 用户（仅 dev profile 可用）
114→     * 请求体: { "users": [{ "userId": 10001, "username": "mock_1", "displayName": "模拟用户1" }, ...] }
115→     */
116→    @PostMapping("/dev/register")
117→    public Result<Integer> devRegister(@RequestBody Map<String, List<Map<String, Object>>> body) {
118→        if (!isDevProfile()) {
119→            return Result.fail(403, "仅 dev 环境可用");
120→        }
121→        List<Map<String, Object>> users = body.get("users");
122→        if (users == null || users.isEmpty()) {
123→            return Result.fail(400, "users 不能为空");
124→        }
125→        int count = 0;
126→        for (Map<String, Object> u : users) {
127→            Long userId = ((Number) u.get("userId")).longValue();
128→            String username = (String) u.get("username");
129→            String displayName = (String) u.get("displayName");
130→            authService.registerMockUser(userId, username, displayName);
131→            count++;
132→        }
133→        return Result.ok(count);
134→    }
135→
136→    /**
137→     * 根据当前请求构建 OAuth2 回调地址
138→     */
139→    private String buildRedirectUri(HttpServletRequest request) {
140→        String scheme = request.getScheme();
141→        String serverName = request.getServerName();
142→        int serverPort = request.getServerPort();
143→
144→        StringBuilder sb = new StringBuilder();
145→        sb.append(scheme).append("://").append(serverName);
146→        // 非标准端口时拼接
147→        if (("http".equals(scheme) && serverPort != 80)
148→                || ("https".equals(scheme) && serverPort != 443)) {
149→            sb.append(":").append(serverPort);
150→        }
151→        sb.append("/api/auth/oauth2/callback");
152→        return sb.toString();
153→    }
154→}
