 1→package com.exam.config;
 2→
 3→import com.exam.util.JwtUtil;
 4→import jakarta.servlet.FilterChain;
 5→import jakarta.servlet.ServletException;
 6→import jakarta.servlet.http.HttpServletRequest;
 7→import jakarta.servlet.http.HttpServletResponse;
 8→import lombok.RequiredArgsConstructor;
 9→import lombok.extern.slf4j.Slf4j;
10→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
11→import org.springframework.security.core.authority.SimpleGrantedAuthority;
12→import org.springframework.security.core.context.SecurityContextHolder;
13→import org.springframework.stereotype.Component;
14→import org.springframework.util.AntPathMatcher;
15→import org.springframework.util.StringUtils;
16→import org.springframework.web.filter.OncePerRequestFilter;
17→
18→import java.io.IOException;
19→import java.util.ArrayList;
20→import java.util.List;
21→
22→/**
23→ * JWT 认证过滤器：从 Authorization header 解析 token 并设置认证信息
24→ */
25→@Slf4j
26→@Component
27→@RequiredArgsConstructor
28→public class JwtAuthenticationFilter extends OncePerRequestFilter {
29→
30→    private static final String BEARER_PREFIX = "Bearer ";
31→    private static final AntPathMatcher PATH_MATCHER = new AntPathMatcher();
32→
33→    /** 白名单路径，直接放行不解析 token */
34→    /** 白名单路径，直接放行不解析 token */
35→    private static final List<String> WHITE_LIST = List.of("/api/auth/oauth2/**");
36→
37→    private final JwtUtil jwtUtil;
38→
39→    @Override
40→    protected void doFilterInternal(HttpServletRequest request,
41→                                    HttpServletResponse response,
42→                                    FilterChain filterChain) throws ServletException, IOException {
43→        String path = request.getRequestURI();
44→
45→        // 白名单路径直接放行
46→        boolean isWhiteListed = WHITE_LIST.stream()
47→                .anyMatch(pattern -> PATH_MATCHER.match(pattern, path));
48→        if (isWhiteListed) {
49→            filterChain.doFilter(request, response);
50→            return;
51→        }
52→
53→        // 解析 Authorization header
54→        String authHeader = request.getHeader("Authorization");
55→        if (StringUtils.hasText(authHeader) && authHeader.startsWith(BEARER_PREFIX)) {
56→            String token = authHeader.substring(BEARER_PREFIX.length());
57→            try {
58→                Long userId = jwtUtil.getUserId(token);
59→                Boolean isAdmin = jwtUtil.getIsAdmin(token);
60→
61→                // 构建权限列表
62→                List<SimpleGrantedAuthority> authorities = new ArrayList<>();
63→                if (Boolean.TRUE.equals(isAdmin)) {
64→                    authorities.add(new SimpleGrantedAuthority("ROLE_ADMIN"));
65→                }
66→                authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
67→
68→                UsernamePasswordAuthenticationToken authentication =
69→                        new UsernamePasswordAuthenticationToken(userId, null, authorities);
70→                SecurityContextHolder.getContext().setAuthentication(authentication);
71→            } catch (Exception e) {
72→                // token 无效或过期，不设认证信息，后续 Security 会返回 401
73→                log.warn("[lbl][Auth][JWT] token 解析失败, path={}, error={}", path, e.getMessage());
74→            }
75→        }
76→
77→        filterChain.doFilter(request, response);
78→    }
79→}
