 22→/**
 23→ * 认证服务：处理 OAuth2 回调、用户查询
 24→ */
 25→@Slf4j
 26→@Service
 27→public class AuthService {
 28→
 29→    private final SysUserMapper sysUserMapper;
 30→    private final JwtUtil jwtUtil;
 31→    private final RestTemplate restTemplate;
 32→
 33→    @Value("${spring.security.oauth2.client.registration.default.client-id}")
 34→    private String clientId;
 35→
 36→    @Value("${spring.security.oauth2.client.registration.default.client-secret}")
 37→    private String clientSecret;
 38→
 39→    @Value("${spring.security.oauth2.client.provider.default.token-uri}")
 40→    private String tokenUri;
 41→
 42→    @Value("${spring.security.oauth2.client.provider.default.user-info-uri}")
 43→    private String userInfoUri;
 44→
 45→    @Value("${spring.security.oauth2.client.provider.default.authorization-uri}")
 46→    private String authorizationUri;
 47→
 48→    public AuthService(SysUserMapper sysUserMapper, JwtUtil jwtUtil) {
 49→        this.sysUserMapper = sysUserMapper;
 50→        this.jwtUtil = jwtUtil;
 51→        this.restTemplate = new RestTemplate();
 52→    }
 53→
 54→    /**
 55→     * 处理 OAuth2 回调：用 code 换 token，获取用户信息，同步到本地用户表，生成 JWT
 56→     *
 57→     * @param code         授权码
 58→     * @param redirectUri  回调地址（需与请求授权时一致）
 59→     * @return JWT token 字符串
 60→     */
 61→    public String handleOAuthCallback(String code, String redirectUri) {
 62→        // 1. 用 code 换 access_token
 63→        String accessToken = exchangeAccessToken(code, redirectUri);
 64→
 65→        // 2. 用 access_token 获取 OA 用户信息
 66→        Map<String, Object> oaUserInfo = fetchOaUserInfo(accessToken);
 67→        String oaUserId = (String) oaUserInfo.get("sub");
 68→        String username = (String) oaUserInfo.get("preferred_username");
 69→        String displayName = (String) oaUserInfo.get("name");
 70→
 71→        // 3. 按 oa_user_id 查库，有则更新，无则创建
 72→        SysUser user = sysUserMapper.selectOne(
 73→                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, oaUserId));
 74→
 75→        if (user != null) {
 76→            user.setUsername(username);
 77→            user.setDisplayName(displayName);
 78→            user.setUpdatedAt(LocalDateTime.now());
 79→            sysUserMapper.updateById(user);
 80→            log.info("[lbl][Auth][LOGIN] 用户登录(已存在), userId={}, oaUserId={}", user.getId(), oaUserId);
 81→        } else {
 82→            user = SysUser.builder()
 83→                    .oaUserId(oaUserId)
 84→                    .username(username)
 85→                    .displayName(displayName)
 86→                    .isAdmin(false)
 87→                    .createdAt(LocalDateTime.now())
 88→                    .updatedAt(LocalDateTime.now())
 89→                    .build();
 90→            sysUserMapper.insert(user);
 91→            log.info("[lbl][Auth][LOGIN] 用户首次登录(新建), userId={}, oaUserId={}", user.getId(), oaUserId);
 92→        }
 93→
 94→        // 4. 生成 JWT
 95→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
 96→    }
 97→
 98→    /**
 99→     * 开发环境登录：直接创建/获取 mock 用户并签发 JWT，跳过 OAuth2 流程
100→     */
101→    public String devLogin() {
102→        String devOaUserId = "dev-mock-001";
103→        SysUser user = sysUserMapper.selectOne(
104→                new LambdaQueryWrapper<SysUser>().eq(SysUser::getOaUserId, devOaUserId));
105→
106→        if (user == null) {
107→            user = SysUser.builder()
108→                    .oaUserId(devOaUserId)
109→                    .username("dev_user")
110→                    .displayName("开发测试用户")
111→                    .isAdmin(true)
112→                    .createdAt(LocalDateTime.now())
113→                    .updatedAt(LocalDateTime.now())
114→                    .build();
115→            sysUserMapper.insert(user);
116→            log.info("[lbl][Auth][LOGIN] Dev 模式: 创建 mock 用户, userId={}", user.getId());
117→        } else {
118→            log.info("[lbl][Auth][LOGIN] Dev 模式: 使用已有 mock 用户, userId={}", user.getId());
119→        }
120→
121→        return jwtUtil.generateToken(user.getId(), user.getIsAdmin());
122→    }
123→
124→    /**
125→     * 注册 mock 用户（仅 dev 环境使用）：按指定 userId 创建用户，已存在则跳过
126→     *
127→     * @param userId      指定的用户 ID
128→     * @param username    用户名
129→     * @param displayName 显示名称
130→     * @return 用户信息
131→     */
132→    public SysUser registerMockUser(Long userId, String username, String displayName) {
133→        SysUser existing = sysUserMapper.selectById(userId);
134→        if (existing != null) {
135→            return existing;
136→        }
137→        SysUser user = SysUser.builder()
138→                .id(userId)
139→                .oaUserId("mock-" + userId)
140→                .username(username)
141→                .displayName(displayName)
142→                .isAdmin(false)
143→                .createdAt(LocalDateTime.now())
144→                .updatedAt(LocalDateTime.now())
145→                .build();
146→        sysUserMapper.insert(user);
147→        log.info("[lbl][Auth][MOCK] 注册 mock 用户, userId={}, username={}", userId, username);
148→        return user;
149→    }
150→
151→    /**
152→     * 获取当前用户信息
153→     *
154→     * @param userId 用户 ID
155→     * @return 用户信息 DTO
156→     */
157→    public UserInfo getCurrentUser(Long userId) {
158→        SysUser user = sysUserMapper.selectById(userId);
159→        if (user == null) {
160→            throw new BizException(ErrorCode.NOT_FOUND);
161→        }
162→
163→        UserInfo info = new UserInfo();
164→        info.setId(user.getId());
165→        info.setOaUserId(user.getOaUserId());
166→        info.setUsername(user.getUsername());
167→        info.setDisplayName(user.getDisplayName());
168→        info.setIsAdmin(user.getIsAdmin());
169→        return info;
170→    }
171→
172→    /**
173→     * 用授权码换取 access_token
174→     */
175→    private String exchangeAccessToken(String code, String redirectUri) {
176→        log.info("[lbl][Auth][OAUTH] 换取 access_token, tokenUri={}, redirectUri={}", tokenUri, redirectUri);
177→        HttpHeaders headers = new HttpHeaders();
178→        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
179→        headers.setBasicAuth(clientId, clientSecret);
180→
181→        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
182→        params.add("grant_type", "authorization_code");
183→        params.add("code", code);
184→        params.add("redirect_uri", redirectUri);
185→
186→        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);
187→
188→        ResponseEntity<Map<String, Object>> response = restTemplate.exchange(
189→                tokenUri,
190→                HttpMethod.POST,
191→                request,
192→                new ParameterizedTypeReference<>() {});
193→
194→        Map<String, Object> body = response.getBody();
195→        if (body == null || !body.containsKey("access_token")) {
